// Deep link configuration model
class DeepLinkConfig {
  final String scheme;
  final String host;
  final String path;
  final Map<String, String> queryParameters;
  final List<String> pathSegments;

  DeepLinkConfig({
    required this.scheme,
    required this.host,
    required this.path,
    required this.queryParameters,
    required this.pathSegments,
  });

  factory DeepLinkConfig.fromUri(Uri uri) {
    return DeepLinkConfig(
      scheme: uri.scheme,
      host: uri.host,
      path: uri.path,
      queryParameters: uri.queryParameters,
      pathSegments: uri.pathSegments,
    );
  }

  @override
  String toString() {
    return 'DeepLinkConfig(scheme: $scheme, host: $host, path: $path, '
        'queryParameters: $queryParameters, pathSegments: $pathSegments)';
  }
}

// Route names
class AppRoutes {
  static const String home = '/';
  static const String profile = '/profile';
  static const String paymentConfirm = '/payment/confirm';
  static const String campaign = '/campaign';
  static const String notFound = '/not-found';
}

// Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    final uri = Uri.tryParse(settings.name ?? '');
    final args = settings.arguments as Map<String, dynamic>? ?? {};

    switch (settings.name) {
      case AppRoutes.home:
        return MaterialPageRoute(
          builder: (_) => const HomeScreen(),
          settings: settings,
        );

      case AppRoutes.profile:
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(
            userId: args['userId'] as String? ?? 'unknown',
            source: args['source'] as String?,
          ),
          settings: settings,
        );

      case AppRoutes.paymentConfirm:
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmScreen(
            transactionId: args['transactionId'] as String?,
            amount: args['amount'] as String?,
            currency: args['currency'] as String?,
            status: args['status'] as String?,
          ),
          settings: settings,
        );

      case AppRoutes.campaign:
        return MaterialPageRoute(
          builder: (_) => CampaignScreen(
            campaignId: args['campaignId'] as String?,
            source: args['source'] as String?,
            medium: args['medium'] as String?,
          ),
          settings: settings,
        );

      default:
        return MaterialPageRoute(
          builder: (_) => NotFoundScreen(
            attemptedRoute: settings.name ?? 'unknown',
          ),
          settings: settings,
        );
    }
  }
}

// Deep Link Handler singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();

  static StreamSubscription<String?>? _linkSubscription;
  static bool _initialLinkHandled = false;

  // Initialize deep link handling
  static Future<void> initialize() async {
    // Handle initial link (app was closed)
    await _handleInitialLink();

    // Handle incoming links (app is running)
    _linkSubscription = uriLinkStream.map((uri) => uri?.toString()).listen(
      (String? link) {
        if (link != null) {
          _processDeepLink(link);
        }
      },
      onError: (err) {
        debugPrint('Deep link stream error: $err');
      },
    );
  }

  static Future<void> _handleInitialLink() async {
    if (_initialLinkHandled) return;
    _initialLinkHandled = true;

    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        // Small delay to ensure navigator is ready
        await Future.delayed(const Duration(milliseconds: 500));
        _processDeepLink(initialLink);
      }
    } catch (e) {
      debugPrint('Error handling initial deep link: $e');
    }
  }

  // Process and route deep links
  static void _processDeepLink(String link) {
    debugPrint('Processing deep link: $link');

    final uri = Uri.tryParse(link);
    if (uri == null) {
      debugPrint('Invalid deep link URI: $link');
      return;
    }

    final config = DeepLinkConfig.fromUri(uri);
    debugPrint('Parsed deep link config: $config');

    // Validate scheme
    if (config.scheme != 'myapp') {
      debugPrint('Unknown scheme: ${config.scheme}');
      return;
    }

    // Route based on host and path
    final fullPath = _buildFullPath(config);
    _routeDeepLink(fullPath, config);
  }

  static String _buildFullPath(DeepLinkConfig config) {
    // For myapp://profile/123, host = "profile", path = "/123"
    // For myapp://payment/confirm, host = "payment", path = "/confirm"
    String fullPath = config.host;
    if (config.path.isNotEmpty && config.path != '/') {
      fullPath += config.path;
    }
    return fullPath;
  }

  static void _routeDeepLink(String fullPath, DeepLinkConfig config) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('Navigator not available');
      return;
    }

    debugPrint('Routing deep link with full path: $fullPath');

    // Match: myapp://profile/123 or myapp://profile/123?source=campaign
    final profileRegex = RegExp(r'^profile/(.+)$');
    final profileMatch = profileRegex.firstMatch(fullPath);

    if (profileMatch != null) {
      final userId = profileMatch.group(1)!;
      navigator.pushNamed(
        AppRoutes.profile,
        arguments: {
          'userId': userId,
          'source': config.queryParameters['source'],
          ...config.queryParameters,
        },
      );
      return;
    }

    // Match: myapp://payment/confirm?transactionId=abc&amount=50&currency=USD
    if (fullPath == 'payment/confirm') {
      navigator.pushNamed(
        AppRoutes.paymentConfirm,
        arguments: {
          'transactionId': config.queryParameters['transactionId'],
          'amount': config.queryParameters['amount'],
          'currency': config.queryParameters['currency'],
          'status': config.queryParameters['status'],
          ...config.queryParameters,
        },
      );
      return;
    }

    // Match: myapp://campaign?id=summer2024&source=email&medium=newsletter
    if (fullPath == 'campaign' || fullPath.startsWith('campaign')) {
      navigator.pushNamed(
        AppRoutes.campaign,
        arguments: {
          'campaignId': config.queryParameters['id'],
          'source': config.queryParameters['source'] ??
              config.queryParameters['utm_source'],
          'medium': config.queryParameters['medium'] ??
              config.queryParameters['utm_medium'],
          ...config.queryParameters,
        },
      );
      return;
    }

    // Fallback: not found
    debugPrint('No route matched for deep link path: $fullPath');
    navigator.pushNamed(
      AppRoutes.notFound,
      arguments: {'attemptedRoute': fullPath},
    );
  }

  // Manually handle a deep link (e.g., from push notification payload)
  static void handleLink(String link) {
    _processDeepLink(link);
  }

  // Dispose subscriptions
  static void dispose() {
    _linkSubscription?.cancel();
    _linkSubscription = null;
  }
}

// Wrapper widget that initializes deep link handling
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

class _DeepLinkWrapperState extends State<DeepLinkWrapper> {
  @override
  void initState() {
    super.initState();
    DeepLinkHandler.initialize();
  }

  @override
  void dispose() {
    DeepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return const HomeScreen();
  }
}

